# -*- coding: utf-8 -*-
import base64
files = {
    "build_index.py": """""",
    "rag_engine.py": """""",
}
for filename, encoded in files.items():
    content = base64.b64decode(encoded).decode("utf-8")
    with open(filename, "w", encoding="utf-8", newline="\n") as f:
        f.write(content)
    print(f"✅ {filename} atualizado ({len(content.splitlines())} linhas)")
